#!/usr/bin/env node
/**
 * Fixes double-slash bug in info_path frontmatter generated by
 * docusaurus-plugin-openapi-docs v4.5.1. The plugin emits `api//spotter-api`
 * instead of `api/spotter-api`, causing the theme's Redux store lookup to
 * return null and crash at runtime.
 */
const fs = require('fs');
const path = require('path');

const docsApiDir = path.join(__dirname, '..', 'docs-api');
if (!fs.existsSync(docsApiDir)) process.exit(0);

const files = fs.readdirSync(docsApiDir).filter(f => f.endsWith('.api.mdx'));
let fixedCount = 0;

for (const file of files) {
  const filePath = path.join(docsApiDir, file);
  const content = fs.readFileSync(filePath, 'utf8');
  const fixed = content.replace(/^(info_path:.*?)\/\//m, '$1/');
  if (fixed !== content) {
    fs.writeFileSync(filePath, fixed);
    fixedCount++;
  }
}

if (fixedCount > 0) {
  console.log(`Fixed double slash in info_path for ${fixedCount} API doc files`);
}
